51	void sigint_handler(int sig) {
52	    Sio_puts("So you think you can stop the bomb with ctrl-c, do you?\n");
53	    sleep(2);
54	    Sio_puts("Well...");
55	    sleep(1);
56	    Sio_puts("OK. :-)\n");
