89	handler_t *Signal(int signum, handler_t *handler) {
90	    struct sigaction action, old_action;
91	    action.sa_handler = handler;
92	    sigemptyset(&action.sa_mask);
93	    action.sa_flags = SA_RESTART;
94	    if (sigaction(signum, &action, &old_action) < 0)
95	        unix_error("Signal error");
96	    return (old_action.sa_handler);
97	}
98	```
99	
100	## 典型的信号处理例子
101	
102	### 不正确的 SIGCHLD 处理
103	
104	信号不会排队，同时发送的多个同类信号只会保留一个。
105	
106	```c
107	void child_handler(int sig) {
108	    int olderrno = errno;
109	    pid_t pid;
110	    if ((pid = wait(NULL)) < 0)
111	        Sio_error("wait error");
112	    ccount--;
113	    errno = olderrno;
114	}
115	```
116	
117	问题：N=5 却只回收了 2 个子进程，因为信号不排队。
118	
119	### 正确的 SIGCHLD 处理
120	
121	必须等待所有终止的子进程，将 wait 放在循环中：
122	
123	```c
124	void child_handler2(int sig) {
125	    int olderrno = errno;
126	    pid_t pid;
127	    while ((pid = wait(NULL)) > 0) {
128	        ccount--;
129	        Sio_puts("Handler reaped child ");
130	        Sio_putl((long)pid);
131	        Sio_puts("\n");
132	    }
133	    if (errno != ECHILD)
134	        Sio_error("wait error");
135	    errno = olderrno;
136	}
137	```
138	
139	### 同步控制流避免并发错误
140	
141	**问题**：在 addjob 前子进程可能已经结束，导致先 deletejob 再 addjob。
142	
143	**解决方案**：在 fork 前阻塞 SIGCHLD，在 addjob 后才恢复。
144	
145	```c
146	int main(int argc, char **argv) {
147	    sigset_t mask_all, mask_one, prev_one;
148	    Sigfillset(&mask_all);
149	    Sigemptyset(&mask_one);
150	    Sigaddset(&mask_one, SIGCHLD);
151	    Signal(SIGCHLD, handler);
152	    initjobs();
153	    while (1) {
154	        Sigprocmask(SIG_BLOCK, &mask_one, &prev_one);  // Block SIGCHLD
155	        if ((pid = Fork()) == 0) {  /* Child */
156	            Sigprocmask(SIG_SETMASK, &prev_one, NULL);  // Unblock SIGCHLD
157	            Execve("/bin/date", argv, NULL);
158	        }
159	        Sigprocmask(SIG_BLOCK, &mask_all, NULL);
160	        addjob(pid);  /* Add the child to the job list */
161	        Sigprocmask(SIG_SETMASK, &prev_one, NULL);
162	    }
163	    exit(0);
164	}
165	```
166	
167	### 使用 sigsuspend 等待信号
168	
169	`sigsuspend` 是一个原子过程：临时解除信号阻塞并挂起进程等待信号，不存在信号丢失的窗口期。
170	
171	```c
172	while (!pid)
173	    Sigsuspend(&prev);  // 原子地同意接收 SIGCHLD 信号以便唤醒
174	```
175	
176	## 非本地跳转：setjmp/longjmp
177	
178	强大（但危险）的用户级机制，用于将控制转移到任意位置，以受控方式打破过程调用/返回的规则。
179	
180	### setjmp
181	
182	```c
183	int setjmp(jmp_buf j);
184	```
185	
186	- 必须在调用 longjmp 之前调用
187	- 设置返回点，记录程序计数器、寄存器上下文和栈指针
188	- 调用一次，返回一次或多次
189	- 返回 0
190	
191	### longjmp
192	
193	```c
194	void longjmp(jmp_buf j, int i);
195	```
196	
197	- 从设置跳转缓冲区 j 的 setjmp 返回一次
198	- 这次 setjmp 返回 i 而不是 0
199	- 调用一次，从不返回
200	
201	### 示例
202	
203	```c
204	jmp_buf buf;
205	int error1 = 0;
206	int error2 = 1;
207	
208	void foo(void) {
209	    if (error1) longjmp(buf, 1);
210	    bar();
211	}
212	void bar(void) {
213	    if (error2) longjmp(buf, 2);
214	}
215	
216	int main() {
217	    switch (setjmp(buf)) {
218	        case 0: foo(); break;
219	        case 1: printf("Detected an error1 condition in foo\n"); break;
220	        case 2: printf("Detected an error2 condition in bar\n"); break;
221	    }
222	    exit(0);
223	}
224	```
225	
226	### 在 C 中模拟 try-catch
227	
228	```c
229	#include <stdio.h>
230	#include <setjmp.h>
231	
232	jmp_buf env;
233	
234	void riskyFunction() {
235	    printf("Starting risky function...\n");
236	    if (1) {  // 模拟错误条件
237	        printf("Error occurred, jumping back...\n");
238	        longjmp(env, 1);  // 跳转回 setjmp 的位置
239	    }
240	}
241	
242	int main() {
243	    if (setjmp(env) == 0) {
244	        riskyFunction();
245	    } else {
246	        printf("Caught an error!\n");
247	    }
248	    printf("Program continues...\n");
249	    return 0;
250	}
251	```
252	
253	### 非本地跳转的限制
254	
255	只能跳转到已被调用但尚未完成的函数的环境，遵循栈的规则。
256	
257	### 典型应用
258	
259	- **深层嵌套的错误处理**：longjmp 直接跳回顶层的 setjmp 位置
260	- **模拟异常处理机制**：在 C 语言中模拟 try-catch
261	- **信号处理中的特殊跳转**：使用 sigsetjmp/siglongjmp
262	- **实现轻量级协程**：保存和恢复 CPU 上下文
263	
264	### 在按下 Ctrl-C 时重启的程序
265	
266	```c
267	#include "csapp.h"
268	sigjmp_buf buf;
269	
270	void handler(int sig) {
271	    siglongjmp(buf, 1);
272	}
273	
274	int main() {
275	    if (!sigsetjmp(buf, 1)) {
276	        Signal(SIGINT, handler);
277	        Sio_puts("starting\n");
278	    } else
279	        Sio_puts("restarting\n");
280	    while (1) {
281	        Sleep(1);
282	        Sio_puts("processing...\n");
283	    }
284	    exit(0);
285	}
286	```
287	
288	## 总结
289	
290	- **信号**提供进程级别的异常处理，需小心编写信号处理程序
291	- **非局部跳转**提供进程内的异常控制流，遵循栈规则的约束
